from typing import List

class Solution:
    def splitIntoFibonacci(self, num: str) -> List[int]:
        def backtrack(start, path):
            if start == len(num):
                return path if len(path) >= 3 else []
            for end in range(start + 1, len(num) + 1):
                if end - start > 1 and num[start] == '0':
                    break
                curr = int(num[start:end])
                if curr >= 2**31:
                    break
                if not path or curr == path[-1] + path[-2]:
                    result = backtrack(end, path + [curr])
                    if result:
                        return result
        return backtrack(0, [])
